function refreshSynchronizedPersonStatus(){const root=document.querySelector('#drawerContent');if(root?.dataset.view!=="person")return;const p=sim.people.find(x=>x.id===root.dataset.id),status=root.querySelector('.person-status-live');if(!p||!status)return;const action=p.currentAction||sim.derivePersonAction(p),place=sim.buildings.find(b=>b.id===action.placeId),destination=sim.buildings.find(b=>b.id===action.destinationId),priority=action.priority||p.actionPriority||0;status.textContent=`${p.age} anos · ${p.role} · ${action.text}`;const card=root.querySelector('[data-current-action]');if(card){card.className=`current-action-card phase-${action.phase}`;const text=card.querySelector('[data-action-text]'),physical=card.querySelector('[data-action-place]'),mode=card.querySelector('[data-action-mode]');if(text)text.textContent=action.text;if(physical)physical.textContent=action.spaceName?`${action.spaceName} · ${place?.name||"local"}`:place?.name||(action.phase==="onboard"?"Dentro do veículo":destination?`A caminho de ${destination.name}`:"Em deslocamento");if(mode)mode.textContent=`${action.mode||"presencial"} · prioridade ${priority>=80?"crítica":priority>=65?"alta":priority>=40?"normal":"flexível"}`;}}
