  const homes = sim.buildings.filter((b) => b.type === "home").sort((a,b)=>(b.occupied/b.capacity)-(a.occupied/a.capacity));
  openDrawer(`<small>MERCADO HABITACIONAL</small><h2>Moradia e expansão</h2><p class="muted">Toda pessoa possui residência ou acomodação temporária</p><div class="stats"><div><small>IMÓVEIS</small><b>${stats.homes}</b></div><div><small>VAGAS</small><b>${stats.vacant}</b></div><div><small>NO HOTEL</small><b>${stats.hotelGuests}</b></div></div><h3>Obras em andamento</h3><div class="project-list">${sim.housingSystem.construction.map((p)=>`<div><span><b>${p.name}</b><small>${p.capacity} moradores · R$ ${p.cost.toLocaleString("pt-BR")}</small></span><em>${p.remaining} sem.</em></div>`).join("")||"<p>Nenhuma obra residencial em andamento.</p>"}</div><h3>Ocupação dos imóveis</h3><div class="housing-list">${homes.map((h)=>`<button data-home="${h.id}"><span><b>${h.name}</b><small>${h.tenure==="rent"?`Aluguel R$ ${h.rent}`:"Propriedade privada"}</small></span><i><b style="width:${Math.min(100,h.occupied/h.capacity*100)}%"></b></i><em>${h.occupied}/${h.capacity}</em></button>`).join("")}</div>${guests.length?`<h3>Hóspedes aguardando moradia</h3><div class="member-list">${guests.map((p)=>`<button data-person="${p.id}"><i style="background:${p.color}">${p.name[0]}</i><span><b>${p.name}</b><small>Recém-chegado</small></span></button>`).join("")}</div>`:""}`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Mercado e anúncios</h3><div class="market-summary"><span>Índice de preços <b>${sim.housingSystem.priceIndex.toFixed(1)}</b></span><span>Aluguel médio <b>R$ ${sim.housingSystem.averageRent}</b></span><span>Despejos <b>${sim.housingSystem.evictions}</b></span></div><div class="listing-grid">${sim.housingSystem.listings.filter(l=>l.status==="available").map(l=>{const home=sim.buildings.find(h=>h.id===l.homeId);return `<button data-home="${home.id}"><b>${home.name}</b><span>${l.type==="sale"?"Venda":"Aluguel"} · R$ ${l.price.toLocaleString("pt-BR")}</span><small>${l.applications.length} candidatura(s)</small></button>`;}).join("")||"<p>Nenhum anúncio disponível.</p>"}</div><h3>Risco habitacional</h3><div class="consumer-list">${sim.families.filter(f=>f.arrears>0).sort((a,b)=>b.arrears-a.arrears).slice(0,10).map(f=>`<div><span><b>Família ${f.surname}</b><small>Crédito ${f.creditScore}</small></span><em>${f.arrears} sem. em atraso</em></div>`).join("")||"<p>Nenhuma família inadimplente.</p>"}</div>`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Evolução urbana</h3><div class="justice-metrics"><span>Expansões da malha <b>${sim.urbanEvolution.expansions}</b></span><span>Obras urbanas <b>${sim.urbanEvolution.projects.length}</b></span><span>Novos equipamentos <b>${sim.urbanEvolution.completed}</b></span><span>Lotes disponíveis <b>${sim.city.lots.filter(l=>!l.occupied).length}</b></span></div><div class="district-growth">${sim.city.districts.map(d=>{const m=sim.urbanEvolution.districtMetrics[d.id];return `<div><span><b>${d.name}</b><small>${m?.residents||0} moradores · ${m?.services||0} serviços · ${m?.crimes||0} crimes</small></span><em>${Math.round(m?.desirability||58)} atratividade</em></div>`;}).join("")}</div><div class="history">${sim.urbanEvolution.history.slice(0,12).map(h=>`<p><b>Semana ${h.week}</b>${h.text}</p>`).join("")||"<p>A expansão urbana ainda não começou.</p>"}</div>`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Mercado imobiliário por oferta e demanda</h3><div class="real-estate-summary"><span><small>UNIDADES</small><b>${market?.totalUnits||0}</b></span><span><small>VACÂNCIA</small><b>${market?Math.round((1-market.occupancyRate)*100):0}%</b></span><span><small>À VENDA</small><b>${market?.listings?.sale||0}</b></span><span><small>PARA ALUGAR</small><b>${market?.listings?.rent||0}</b></span><span><small>PREÇO MEDIANO</small><b>R$ ${Math.round(market?.listings?.medianSalePrice||0).toLocaleString("pt-BR")}</b></span><span><small>ALUGUEL MEDIANO</small><b>R$ ${Math.round(market?.listings?.medianRent||0).toLocaleString("pt-BR")}</b></span></div><div class="district-market">${(market?.districts||[]).map(district=>`<div><span><b>${sim.city.districts.find(item=>item.id===district.districtId)?.name||district.name}</b><small>maior procura: ${district.strongestDemandType||"—"}</small></span><em>pressão ${district.pressure.toFixed(2)}</em><i><b style="width:${Math.min(100,district.pressure*55)}%"></b></i></div>`).join("")}</div><h3>Incorporações em cinco etapas</h3><div class="development-pipeline">${development.filter(project=>project.status==="active").map(project=>{const phase=project.phases[project.phaseIndex];return `<article><span><small>${project.typeId.replaceAll("_"," ").toUpperCase()}</small><b>${project.name}</b><em>${phase?.label||project.status} · ${Math.round((project.phaseProgress||0)*100)}%</em></span><i><b style="width:${Math.round((project.progress||0)*100)}%"></b></i><footer>${project.units} unidade(s) · lote ${Math.round(project.lotArea)} m² · entrega em ${project.remainingWeeks} sem.</footer></article>`;}).join("")||"<p>Nenhuma incorporação privada em andamento.</p>"}</div><h3>Expansão pública e pavimentação</h3><div class="public-works-list">${[...(sim.urbanEvolution.expansionProjects||[]).filter(project=>project.status==="active").map(project=>({name:sim.city.districts.find(d=>d.id===project.districtId)?.name||"Novo bairro",stage:project.phaseLabel,progress:(project.phaseIndex+project.phaseProgress)/5*100,detail:`${project.lotIds.length} terrenos · R$ ${project.investment.toLocaleString("pt-BR")}`})),...municipalWorks.filter(work=>work.status!=="completed").map(work=>({name:work.name,stage:work.stage,progress:work.progress,detail:`R$ ${Math.round(work.spent).toLocaleString("pt-BR")} / ${Math.round(work.budget).toLocaleString("pt-BR")}`}))].map(work=>`<article><span><b>${work.name}</b><small>${work.stage} · ${work.detail}</small></span><em>${Math.round(work.progress)}%</em><i><b style="width:${work.progress}%"></b></i></article>`).join("")||"<p>Nenhuma obra territorial ativa.</p>"}</div>`);
