function showJusticeRecord(p) {
  openDrawer(`<small>REGISTRO JUDICIAL</small><h2>${p.name}</h2><p class="muted">${p.justice.convictions} condenações · ${p.justice.arrests} prisões</p><div class="stats"><div><small>MULTAS</small><b>R$ ${p.justice.fines.toLocaleString("pt-BR")}</b></div><div><small>OCORRÊNCIAS</small><b>${p.justice.offenses.length}</b></div><div><small>SITUAÇÃO</small><b>${p.justice.incarcerated ? `${p.justice.sentenceRemaining} dias` : "Livre"}</b></div></div><h3>Histórico legal</h3><div class="history">${p.justice.history.map((h)=>`<p><b>Semana ${h.week}</b>${h.text}</p>`).join("")||"<p>Nenhum antecedente registrado.</p>"}</div><button class="primary" id="backJustice">Voltar ao morador</button>`);
  document.querySelector("#backJustice").insertAdjacentHTML("beforebegin",`<h3>Antecedentes e cumprimento</h3><div class="record-card status-${p.justice.recordPoints>=5?"grave":"regular"}"><span><small>STATUS DA FICHA</small><b>${p.justice.recordStatus}</b></span><span><small>PONTOS</small><b>${p.justice.recordPoints}</b></span><span><small>REABILITAÇÃO</small><b>${Math.round(p.justice.rehabilitation)}%</b></span><span><small>DISCIPLINA</small><b>${p.justice.disciplinary} sanções</b></span><span><small>TRABALHO INTERNO</small><b>${p.justice.prisonJob||"—"}</b></span><span><small>REGIME</small><b>${p.justice.parole?"Condicional":p.justice.incarcerated?"Fechado":"Livre"}</b></span></div>`);
  document.querySelector("#backJustice").onclick=()=>showPerson(p);
}
function showCriminalCase(c){
  const file=sim.investigationFile(c.investigationId||c.id),o=offenses.find(x=>x.id===c.offenseId),trial=sim.justiceSystem.courtQueue.find(t=>t.caseId===c.id);
  if(!file){
    const victim=sim.people.find(p=>p.id===c.victimId),suspect=sim.people.find(p=>p.id===c.suspectId),officer=sim.people.find(p=>p.id===c.assignedOfficerId);
    openDrawer(`<small>INQUÉRITO POLICIAL</small><h2>${o?.name||"Ocorrência"}</h2><p class="muted">${c.status} · prioridade ${c.priority}/5</p><div class="stats"><div><small>PROGRESSO</small><b>${Math.round(c.progress)}%</b></div><div><small>FORÇA PROBATÓRIA</small><b>${Math.round(c.evidenceStrength)}</b></div><div><small>TESTEMUNHAS</small><b>${c.witnesses}</b></div></div><h3>Partes e despacho</h3><dl><dt>Vítima</dt><dd>${victim?.name||"Sem vítima individual"}</dd><dt>Suspeito</dt><dd>${suspect?.name||"Não identificado"}</dd><dt>Responsável</dt><dd>${officer?.name||"Aguardando designação"}</dd></dl>`);
    return;
  }
  const clock=value=>value?.label||`Semana ${value?.week??"—"}`,lead=file.people.leadInvestigator,suspects=file.people.suspects.filter(item=>!item.excludedAt),primarySuspect=suspects[0]?.person;
  openDrawer(`<small>INQUÉRITO POLICIAL · ACOMPANHAMENTO EM TEMPO REAL</small><h2>${file.overview.offenseLabel}</h2><p class="muted">${file.overview.status.replaceAll("_"," ")} · prioridade ${file.overview.priority}/5 · aberto em ${clock(file.overview.openedAt)}</p><div class="stats investigation-stats"><div><small>PROGRESSO</small><b>${Math.round(file.progress.overall)}%</b></div><div><small>CONFIANÇA</small><b>${Math.round(file.progress.confidence)}%</b></div><div><small>VESTÍGIOS</small><b>${file.evidence.length}</b></div><div><small>OITIVAS</small><b>${file.statements.length}</b></div></div><div class="investigation-progress">${[["Cena",file.progress.scene],["Evidências",file.progress.evidence],["Depoimentos",file.progress.interviews],["Autoria",file.progress.suspect],["Medidas legais",file.progress.legal]].map(([label,value])=>`<span><small>${label}</small><b>${Math.round(value)}%</b><i><b style="width:${value}%"></b></i></span>`).join("")}</div><h3>Partes e responsabilidade</h3><dl><dt>Vítima(s)</dt><dd>${file.people.victims.map(person=>person.name).join(", ")||"Sem vítima individual"}</dd><dt>Pessoa(s) investigada(s)</dt><dd>${suspects.map(item=>item.person?.name||"Identidade sob apuração").join(", ")||"Autoria ainda não individualizada"}</dd><dt>Responsável</dt><dd>${lead?.name||"Aguardando designação"}</dd><dt>Tribunal</dt><dd>${trial?.status||"Ainda no inquérito"}</dd></dl>${file.progress.blockers.length?`<div class="investigation-blockers"><small>PENDÊNCIAS ATUAIS</small>${file.progress.blockers.map(text=>`<span>${text}</span>`).join("")}</div>`:""}<details open class="case-section"><summary>Cenas e diligências <em>${file.scenes.length+file.diligences.length}</em></summary><div class="case-grid">${file.scenes.map(scene=>`<article><small>CENA · ${scene.status||"processamento"}</small><b>${scene.place?.name||"Local registrado"}</b><span>${scene.releasedAt?`Liberada em ${clock(scene.releasedAt)}`:"Preservação e coleta em andamento"}</span></article>`).join("")}${file.diligences.map(item=>`<article><small>${item.status}</small><b>${item.label}</b><span>${item.result||"Aguardando execução ou resultado"}</span></article>`).join("")}</div></details><details open class="case-section"><summary>Evidências e cadeia de custódia <em>${file.evidence.length}</em></summary><div class="evidence-list rich">${file.evidence.map(e=>`<div><span><b>${e.label}</b><small>${e.status.replaceAll("_"," ")} · ${e.forensic.discipline||"registro policial"} · selo ${e.sealId}</small><small>${e.custody.length} movimentação(ões) na cadeia de custódia</small></span><em>força ${Math.round(e.strength)}</em></div>`).join("")||"<p>Nenhum vestígio catalogado.</p>"}</div></details><details class="case-section"><summary>Hipóteses, oitivas e mandados <em>${file.hypotheses.length+file.statements.length+file.warrants.length}</em></summary><div class="case-grid">${file.hypotheses.map(item=>`<article><small>HIPÓTESE · ${item.status}</small><b>${item.label}</b><span>${Math.round(item.probability)}% · ${item.suspect?.name||"sem autoria individualizada"}</span></article>`).join("")}${file.statements.map(item=>`<article><small>OITIVA · ${item.status}</small><b>${item.person?.name||"Pessoa protegida"}</b><span>${clock(item.takenAt)}</span></article>`).join("")}${file.warrants.map(item=>`<article><small>MANDADO · ${item.status}</small><b>${item.type}</b><span>${clock(item.authorizedAt||item.requestedAt)}</span></article>`).join("")}</div><p class="legal-presumption">Hipóteses e pessoas investigadas não equivalem a condenação.</p></details><details open class="case-section"><summary>Linha do tempo <em>${file.timeline.length}</em></summary><div class="history case-timeline">${file.timeline.map(item=>`<p><b>${clock(item.at)} · ${item.title}</b>${item.detail}</p>`).join("")}</div></details>${file.resolution?`<div class="case-resolution"><small>CONCLUSÃO INVESTIGATIVA</small><b>${file.resolution.status}</b><span>Confiança ${Math.round(file.resolution.confidence||file.progress.confidence)}%. O julgamento permanece a cargo do Judiciário.</span></div>`:""}${primarySuspect?`<button class="primary" id="caseSuspect">Abrir ficha da pessoa investigada</button>`:""}`);
  if(primarySuspect)document.querySelector("#caseSuspect").onclick=()=>showJusticeRecord(sim.people.find(person=>person.id===primarySuspect.id));
}

function showJusticeDashboard() {
  const js=sim.justiceSystem, prisoners=js.prisoners.map((id)=>sim.people.find((p)=>p.id===id));
  const recent=(sim.investigationSummary?.priorityCases||[]).map(row=>js.openCases.find(item=>item.id===row.sourceCaseId)).filter(Boolean).concat(js.openCases.slice(-12).reverse()).filter((item,index,all)=>all.findIndex(other=>other.id===item.id)===index).slice(0,12),investigation=sim.investigationSummary;
  openDrawer(`<small>SEGURANÇA E JUSTIÇA</small><h2>Delegacia Municipal</h2><p class="muted">Patrulhamento, investigação e sistema prisional</p><div class="stats"><div><small>CASOS</small><b>${js.reported}</b></div><div><small>SOLUCIONADOS</small><b>${js.solved}</b></div><div><small>PRESOS</small><b>${prisoners.length}/${js.prisonCapacity}</b></div></div><div class="justice-metrics"><span>Mandados <b>${js.warrants.length}</b></span><span>Fila pericial <b>${js.evidenceLab.queue.length}</b></span><span>Tribunal <b>${js.courtQueue.filter(t=>!["condenado","absolvido"].includes(t.status)).length}</b></span><span>Resposta média <b>${js.responseMinutes} min</b></span><span>Condenações <b>${js.convictions}</b></span><span>Absolvições <b>${js.acquittals}</b></span></div><h3>Inquéritos recentes</h3><div class="case-list">${recent.map((c)=>{const o=offenses.find((x)=>x.id===c.offenseId),suspect=sim.people.find((p)=>p.id===c.suspectId);return `<button data-case="${c.id}"><i class="severity-${o.severity}"></i><span><b>${o.name}</b><small>${suspect?.name||"Suspeito não identificado"} · ${c.status}</small></span><em>${Math.round(c.progress)}%</em></button>`;}).join("")||"<p>Nenhuma ocorrência registrada.</p>"}</div>${prisoners.length?`<h3>População prisional</h3><div class="member-list">${prisoners.map((p)=>`<button data-suspect="${p.id}"><i style="background:${p.color}">${p.name[0]}</i><span><b>${p.name}</b><small>${p.justice.pretrial?"Prisão provisória":`${p.justice.sentenceRemaining} dias · cela ${p.justice.cell}`}</small></span></button>`).join("")}</div>`:""}`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Reabilitação prisional</h3><div class="justice-metrics"><span>Liberdades condicionais <b>${js.paroles}</b></span><span>Reabilitados <b>${js.rehabilitated}</b></span><span>Incidentes disciplinares <b>${js.incidents}</b></span>${js.programs.map(p=>`<span>Programa ativo <b>${p}</b></span>`).join("")}</div>`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Alas penitenciárias</h3><div class="prison-wings">${js.prisonWings.map(w=>`<div><span><b>${w.name}</b><small>${w.inmates.length}/${w.capacity} ocupados</small></span><i><b style="width:${Math.min(100,w.inmates.length/w.capacity*100)}%"></b></i></div>`).join("")}</div>`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Economia clandestina</h3><div class="justice-metrics"><span>Esquemas monitorados <b>${sim.underground.enterprises.length}</b></span><span>Operações realizadas <b>${sim.underground.operations}</b></span><span>Valores apreendidos <b>R$ ${Math.round(sim.underground.seized).toLocaleString("pt-BR")}</b></span><span>Dinheiro lavado <b>R$ ${Math.round(sim.underground.laundered).toLocaleString("pt-BR")}</b></span></div><div class="scheme-list">${sim.underground.enterprises.map(s=>{const b=sim.businesses.find(x=>x.id===s.businessId);return `<button data-scheme-business="${b.buildingId}"><span><b>${b.name}</b><small>${s.front} · ${s.status}</small></span><em>Risco ${Math.round(s.heat)}%</em></button>`;}).join("")}</div>`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Operação policial e atendimento às vítimas</h3><div class="justice-metrics"><span>Chamados recentes <b>${sim.justiceSystem.emergencyCalls.length}</b></span><span>Tempo de resposta <b>${sim.justiceSystem.responseMinutes} min</b></span><span>Vítimas assistidas <b>${sim.justiceSystem.victimSupport.length}</b></span><span>Mandados ativos <b>${sim.justiceSystem.warrants.filter(w=>w.status!=="cumprido").length}</b></span></div><div class="district-growth">${sim.city.districts.map(d=>{const m=sim.justiceSystem.districtCrime[d.id]||{reported:0,violent:0,solved:0};return `<div><span><b>${d.name}</b><small>${m.reported} caso(s) · ${m.violent} violento(s)</small></span><em>${m.solved} solucionado(s)</em></div>`;}).join("")}</div>`);
  if(investigation)document.querySelector("#drawerContent").insertAdjacentHTML("afterbegin",`<div class="investigation-command"><small>CENTRAL INVESTIGATIVA</small><span><b>${investigation.totals.active}</b> ativos</span><span><b>${investigation.totals.elucidated}</b> elucidados</span><span><b>${investigation.totals.homicideActive}</b> homicídios ativos</span><span><b>${investigation.lab.activeEvidenceIds.length}</b> análises no laboratório</span></div>`);
  document.querySelector("#drawerContent").dataset.view="justice";
  document.querySelectorAll("[data-suspect]").forEach((b)=>(b.onclick=()=>showJusticeRecord(sim.people.find((p)=>p.id===b.dataset.suspect))));
  document.querySelectorAll("[data-case]").forEach((b)=>(b.onclick=()=>showCriminalCase(js.openCases.find(c=>c.id===b.dataset.case))));
  document.querySelectorAll("[data-scheme-business]").forEach(b=>b.onclick=()=>showBuilding(sim.buildings.find(x=>x.id===b.dataset.schemeBusiness)));
}

