  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Desempenho da rede</h3><div class="route-performance">${ts.routes.map(r=>`<div><span><b>${r.name}</b><small>A cada ${r.frequency} min · ${r.completedTrips} voltas</small></span><em>${Math.round(r.punctuality)}% pontual</em></div>`).join("")}</div><div class="market-summary"><span>Espera média <b>${Math.round(ts.averageWait)} min</b></span><span>Panes <b>${ts.breakdowns}</b></span><span>Manutenção <b>R$ ${Math.round(ts.maintenanceCost).toLocaleString("pt-BR")}</b></span></div>`);
  document.querySelector("#drawerContent").insertAdjacentHTML("beforeend",`<h3>Sistema de táxis</h3><div class="taxi-summary"><span><small>FROTA</small><b>${taxi?.fleet||0}</b></span><span><small>DISPONÍVEIS</small><b>${taxi?.available||0}</b></span><span><small>CORRIDAS ATIVAS</small><b>${taxi?.activeRides||0}</b></span><span><small>CONCLUÍDAS</small><b>${taxi?.completed||0}</b></span><span><small>ESPERA MÉDIA</small><b>${taxi?.averageWait||0} min</b></span><span><small>RECEITA</small><b>R$ ${(taxi?.revenue||0).toLocaleString("pt-BR")}</b></span></div><div class="member-list">${taxiDrivers.map(driver=>`<button data-driver="${driver.id}"><i style="background:${driver.color}">${driver.name[0]}</i><span><b>${driver.name}</b><small>${driver.shift?.name||"Escala de táxi"}</small></span></button>`).join("")||"<p>Nenhum taxista escalado.</p>"}</div>`);
