function setMapZoom(nextScale,clientX,clientY){const rect=canvas.getBoundingClientRect(),screenX=(clientX??(rect.left+rect.width/2))-rect.left,screenY=(clientY??(rect.top+rect.height/2))-rect.top,before=coords(),worldX=(screenX-before.ox)/before.cell,worldY=(screenY-before.oy)/before.cell;nextScale=Math.max(.55,Math.min(2.4,nextScale));if(Math.abs(nextScale-scale)<.001)return;scale=nextScale;const after=coords();camera.panX+=screenX-(after.ox+worldX*after.cell);camera.panY+=screenY-(after.oy+worldY*after.cell);baseMapSignature="";const badge=document.querySelector("#zoomIndicator");badge.textContent=`${Math.round(scale*100)}%`;badge.classList.add("show");clearTimeout(zoomIndicatorTimer);zoomIndicatorTimer=setTimeout(()=>badge.classList.remove("show"),700);draw();}
let dragState=null,suppressMapClick=false;
canvas.addEventListener("pointerdown",e=>{dragState={x:e.clientX,y:e.clientY,startX:e.clientX,startY:e.clientY};canvas.setPointerCapture(e.pointerId);canvas.classList.add("dragging");});
canvas.addEventListener("pointermove",e=>{if(!dragState)return;const dx=e.clientX-dragState.x,dy=e.clientY-dragState.y;if(Math.hypot(e.clientX-dragState.startX,e.clientY-dragState.startY)>4){suppressMapClick=true;if(!citizenFocusId)camera.followId=null;camera.panX+=dx;camera.panY+=dy;dragState.x=e.clientX;dragState.y=e.clientY;draw();}});
canvas.addEventListener("pointerup",e=>{dragState=null;canvas.releasePointerCapture(e.pointerId);canvas.classList.remove("dragging");setTimeout(()=>suppressMapClick=false,0);});
canvas.addEventListener("wheel",e=>{e.preventDefault();const delta=e.deltaMode===1?e.deltaY*16:e.deltaMode===2?e.deltaY*canvas.clientHeight:e.deltaY,setBy=Math.exp(-delta*.0015);setMapZoom(scale*setBy,e.clientX,e.clientY);},{passive:false});
canvas.addEventListener("click", (e) => {
  if(suppressMapClick)return;
  const r = canvas.getBoundingClientRect(),
    { cell, ox, oy } = coords(),
    x = (e.clientX - r.left - ox) / cell,
    y = (e.clientY - r.top - oy) / cell;
  let p = sim.people.find((p) => Math.hypot(p.x - x, p.y - y) < 0.35);
  if (p) return citizenFocusId?enterCitizenFocus(p):showPerson(p);
  const b = sim.buildings.find(
    (b) => x >= b.x && x <= b.x + b.w && y >= b.y && y <= b.y + b.h,
  );
  if (b) citizenFocusId?openFocusPlace(b):showBuilding(b);
});
